mapper.sql:
instance_id=#{instanceId} AND collect_time BETWEEN #{from} AND #{to}
AND database_name=#{database}
AND user_name=#{user}
AND query_id=#{queryId}

mapper.select:
SELECT 
FROM pg_query_stat_history
WHERE 
GROUP BY database_name,user_name,query_id
ORDER BY ${orderBy}
LIMIT #{limit} OFFSET #{offset}

SELECT id,database_name,query_id,query_text,regression_type,severity,
       baseline_from,baseline_to,current_from,current_to,baseline_value,
       current_value,change_ratio,evidence,detected_at
  FROM pg_sql_regression_event WHERE instance_id=#{instanceId}
 ORDER BY detected_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT id,plan_hash,node_summary,captured_at FROM pg_plan_history
 WHERE instance_id=#{instanceId} AND database_name=#{database} AND query_id=#{queryId}
 ORDER BY captured_at DESC LIMIT 1

SELECT id,database_name,query_id,sql_hash,plan_hash,previous_plan_hash,
       plan_changed,plan_json,node_summary,captured_at
  FROM pg_plan_history
 WHERE instance_id=#{instanceId} AND database_name=#{database} AND query_id=#{queryId}
 ORDER BY captured_at DESC LIMIT #{limit}
